import React, { useState, useEffect, useRef } from 'react';

const n = (v: any) => { const num = parseFloat(v); return isNaN(num) ? 0 : num; };
const fmt = (v: number) => v.toFixed(2).replace(/\.00$/, '');
const STORAGE_KEY = 'structural';

const SectionTitle = ({ children }: any) => (
  <div style={{ position: 'relative', padding: '8px 12px', marginBottom: '12px', marginTop: '8px', background: 'linear-gradient(to left, transparent, #e8f0fe 30%)', borderRight: '4px solid #2563eb', borderRadius: '0 8px 8px 0', boxShadow: '0 0 8px rgba(37,99,235,0.1)' }}>
      <span style={{ fontSize: '0.8rem', fontWeight: 800, color: '#003366' }}>{children}</span>
        </div>
        );

        const Num = ({ id, label, value, set, unit, readOnly }: any) => {
          const inputRef = useRef<HTMLInputElement>(null);
            useEffect(() => { if (inputRef.current) inputRef.current.value = value; }, []);
              const save = () => { if (inputRef.current && !readOnly) set(inputRef.current.value); };
                return (
                    <div style={{ background: readOnly ? '#f0fdf4' : '#fdfdfd', border: '1px solid #ddd', borderRadius: '8px', padding: '8px 5px', textAlign: 'center' }}>
                          <label style={{ fontSize: '0.6rem', color: '#003366', display: 'block', marginBottom: '2px', fontWeight: 700 }}>{label}</label>
                                <input id={id} type="text" inputMode="decimal" autoComplete="off" ref={inputRef} defaultValue={value} onBlur={save} onFocus={e => e.target.select()} readOnly={readOnly} style={{ width: '100%', border: 'none', textAlign: 'center', fontSize: '0.85rem', padding: '2px 0', outline: 'none', background: 'transparent', fontWeight: readOnly ? 800 : 700, fontFamily: 'Cairo, sans-serif', color: readOnly ? '#059669' : '#003366' }} />
                                      {unit && <span style={{ fontSize: '0.55rem', color: '#888', display: 'block', marginTop: '2px' }}>{unit}</span>}
                                          </div>
                                            );
                                            };

                                            const getInitial = () => {
                                              try { const stored = localStorage.getItem(STORAGE_KEY); if (stored) return JSON.parse(stored); } catch (e) {}
                                                return {
                                                    buildingArea: '300', floors: '2', safetyFactor: '1.10',
                                                        soilCapacity: '15', columnCount: '20',
                                                            fLength: '1.60', fWidth: '1.60', fHeight: '0.5',
                                                                fColLength: '0.30', fColWidth: '0.30',
                                                                    cLoad: '40', cLength: '0.30', cWidth: '0.30', cFcu: '25',
                                                                        cBarCount: '8', cBarDia: '16',
                                                                          };
                                                                          };

                                                                          const Structural: React.FC = () => {
                                                                            const [data, setData] = useState<any>(getInitial);
                                                                              useEffect(() => { localStorage.setItem(STORAGE_KEY, JSON.stringify(data)); }, [data]);
                                                                                const update = (k: string, v: string) => setData((prev: any) => ({ ...prev, [k]: v }));
                                                                                  const reset = () => setData(getInitial());

                                                                                    // الثوابت
                                                                                      const LOAD_PER_SQM = 1.5;

                                                                                        const A = n(data.buildingArea), N = n(data.floors);
                                                                                          const sf = n(data.safetyFactor), sc = n(data.soilCapacity);
                                                                                            const colCnt = n(data.columnCount) || 1;

                                                                                              const floorWeight = A * LOAD_PER_SQM;
                                                                                                const totalLoad = floorWeight * N * sf;
                                                                                                  const colLoad = totalLoad / colCnt;
                                                                                                    const totalFootingArea = sc > 0 ? totalLoad / sc : 0;
                                                                                                      const avgFootingArea = colCnt > 0 ? totalFootingArea / colCnt : 0;
                                                                                                        const suggestedFootingSide = Math.sqrt(avgFootingArea);

                                                                                                          const fL = n(data.fLength), fW = n(data.fWidth), fH = n(data.fHeight);
                                                                                                            void fH;
                                                                                                              const fColL = n(data.fColLength), fColW = n(data.fColWidth);
                                                                                                                const fActualArea = fL * fW;
                                                                                                                  const fPressure = fActualArea > 0 ? colLoad / fActualArea : 0;
                                                                                                                    const fUtilization = sc > 0 ? (fPressure / sc) * 100 : 0;
                                                                                                                      const fSafe = fPressure <= sc;

                                                                                                                        const overhangL = (fL - fColL) / 2;
                                                                                                                          const overhangW = (fW - fColW) / 2;

                                                                                                                            const fRequiredArea = sc > 0 ? colLoad / sc : 0;
                                                                                                                              const fSuggestedSide = Math.sqrt(fRequiredArea);

                                                                                                                                const cLoadVal = n(data.cLoad);
                                                                                                                                  const cL = n(data.cLength), cW = n(data.cWidth), cFcu = n(data.cFcu);
                                                                                                                                    const cAg = cL * cW;
                                                                                                                                      const cCapacity = cAg * cFcu * 30;
                                                                                                                                        const utilization = cCapacity > 0 ? (cLoadVal / cCapacity) * 100 : 0;
                                                                                                                                          const cSafe = utilization <= 100;

                                                                                                                                            const cBars = n(data.cBarCount), cDia = n(data.cBarDia);
                                                                                                                                              const barAreaCm2 = Math.PI * (cDia / 10) * (cDia / 10) / 4;
                                                                                                                                                const totalSteelCm2 = cBars * barAreaCm2;
                                                                                                                                                  const colAreaCm2 = cL * cW * 10000;
                                                                                                                                                    const steelRatio = colAreaCm2 > 0 ? (totalSteelCm2 / colAreaCm2) * 100 : 0;
                                                                                                                                                      const steelRatioOK = steelRatio >= 1 && steelRatio <= 4;

                                                                                                                                                        const cRequiredArea = cFcu > 0 ? cLoadVal / (cFcu * 35) : 0;
                                                                                                                                                          const cSuggestedSide = Math.sqrt(cRequiredArea);

                                                                                                                                                            const soilOK = sc >= 10;
                                                                                                                                                              const footingFinalOK = fSafe;
                                                                                                                                                                const columnFinalOK = cSafe;
                                                                                                                                                                  const steelFinalOK = steelRatioOK;
                                                                                                                                                                    const allOK = soilOK && footingFinalOK && columnFinalOK && steelFinalOK;

                                                                                                                                                                      const calculate = () => { localStorage.setItem(STORAGE_KEY, JSON.stringify(data)); };const [openMain, setOpenMain] = useState(true);
                                                                                                                                                                      const [openFooting, setOpenFooting] = useState(false);
                                                                                                                                                                      const [openColumn, setOpenColumn] = useState(false);
                                                                                                                                                                      const [openFinal, setOpenFinal] = useState(true);

                                                                                                                                                                      return (
                                                                                                                                                                        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                                                                                                                                                                            {/* تنبيه */}
                                                                                                                                                                                <div style={{ background: '#fef3c7', border: '1px solid #f59e0b', borderRadius: '12px', padding: '12px', fontSize: '0.75rem', color: '#92400e', fontWeight: 600, display: 'flex', alignItems: 'center', gap: '8px' }}>
                                                                                                                                                                                      <span style={{ fontSize: '1.2rem' }}>⚠️</span>
                                                                                                                                                                                            <span>تشييك تقريبي للمبنى والقواعد والأعمدة قبل التصميم. هذه الحسابات أولية ولا تغني عن التصميم الإنشائي النهائي.</span>
                                                                                                                                                                                                </div>

                                                                                                                                                                                                    {/* بيانات المبنى العامة */}
                                                                                                                                                                                                        <div className="model-card" style={{ border: '1px solid #ddd', borderRadius: '12px', overflow: 'hidden', background: 'white' }}>
                                                                                                                                                                                                              <div className="model-head" onClick={() => setOpenMain(!openMain)} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 12px', background: '#f8fafc', cursor: 'pointer' }}>
                                                                                                                                                                                                                      <span style={{ fontWeight: 700, color: '#003366', fontSize: '0.9rem' }}>📋 بيانات المبنى العامة</span>
                                                                                                                                                                                                                              <span>{openMain ? '▲' : '▼'}</span>
                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                          {openMain && (
                                                                                                                                                                                                                                                  <div className="model-body" style={{ padding: '10px 12px' }}>
                                                                                                                                                                                                                                                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', marginBottom: '12px' }}>
                                                                                                                                                                                                                                                                        <Num id="s-ba" label="مساحة المبنى (م²)" value={data.buildingArea} set={(v: string) => update('buildingArea', v)} unit="م²" />
                                                                                                                                                                                                                                                                                    <Num id="s-fl" label="عدد الأدوار" value={data.floors} set={(v: string) => update('floors', v)} unit="دور" />
                                                                                                                                                                                                                                                                                                <Num key={fmt(floorWeight)} id="s-fld" label="حمل الدور (طن)" value={fmt(floorWeight)} set={() => {}} unit="طن" readOnly />
                                                                                                                                                                                                                                                                                                            <Num id="s-sf" label="معامل الأمان" value={data.safetyFactor} set={(v: string) => update('safetyFactor', v)} />
                                                                                                                                                                                                                                                                                                                        <Num id="s-sc" label="قدرة تحمل التربة (طن/م²)" value={data.soilCapacity} set={(v: string) => update('soilCapacity', v)} unit="طن/م²" />
                                                                                                                                                                                                                                                                                                                                    <Num id="s-cc" label="عدد الأعمدة" value={data.columnCount} set={(v: string) => update('columnCount', v)} unit="عمود" />
                                                                                                                                                                                                                                                                                                                                              </div>

                                                                                                                                                                                                                                                                                                                                                        <SectionTitle>نتائج التقدير العام</SectionTitle>
                                                                                                                                                                                                                                                                                                                                                                  <div className="results-grid" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
                                                                                                                                                                                                                                                                                                                                                                              <div className="result-tile" style={{ border: '1px solid #2563eb', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#e8f0fe' }}><span style={{ fontSize: '0.55rem', color: '#1e40af' }}>الحمل الكلي للمبنى</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(totalLoad)} طن</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                          <div className="result-tile" style={{ border: '1px solid #2563eb', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#e8f0fe' }}><span style={{ fontSize: '0.55rem', color: '#1e40af' }}>حمل العمود التقريبي</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(colLoad)} طن</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                      <div className="result-tile" style={{ border: '1px solid #d97706', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#fef3c7' }}><span style={{ fontSize: '0.55rem', color: '#92400e' }}>مساحة القواعد المطلوبة</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(totalFootingArea)} م²</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="result-tile" style={{ border: '1px solid #d97706', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#fef3c7' }}><span style={{ fontSize: '0.55rem', color: '#92400e' }}>متوسط مساحة القاعدة</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(avgFootingArea)} م²</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="result-tile" style={{ border: '1px solid #059669', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#ecfdf5' }}><span style={{ fontSize: '0.55rem', color: '#065f46' }}>قاعدة مقترحة (مربعة)</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(suggestedFootingSide)} × {fmt(suggestedFootingSide)} م</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                      )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                              {/* دراسة قاعدة نموذجية */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="model-card" style={{ border: '1px solid #ddd', borderRadius: '12px', overflow: 'hidden', background: 'white' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="model-head" onClick={() => setOpenFooting(!openFooting)} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 12px', background: '#f8fafc', cursor: 'pointer' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <span style={{ fontWeight: 700, color: '#003366', fontSize: '0.9rem' }}>🧱 تشييك قاعدة فعلية</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <span>{openFooting ? '▲' : '▼'}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {openFooting && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="model-body" style={{ padding: '10px 12px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', marginBottom: '12px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <Num id="s-flen" label="طول القاعدة (م)" value={data.fLength} set={(v: string) => update('fLength', v)} unit="م" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <Num id="s-fwid" label="عرض القاعدة (م)" value={data.fWidth} set={(v: string) => update('fWidth', v)} unit="م" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <Num id="s-fh" label="ارتفاع القاعدة (م)" value={data.fHeight} set={(v: string) => update('fHeight', v)} unit="م" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <Num id="s-fsc" label="قدرة التربة (طن/م²)" value={data.soilCapacity} set={(v: string) => update('soilCapacity', v)} unit="طن/م²" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <Num id="s-fcl" label="طول العمود (م)" value={data.fColLength} set={(v: string) => update('fColLength', v)} unit="م" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <Num id="s-fcw" label="عرض العمود (م)" value={data.fColWidth} set={(v: string) => update('fColWidth', v)} unit="م" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <SectionTitle>نتائج تشييك القاعدة</SectionTitle>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="results-grid" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="result-tile" style={{ border: '1px solid #2563eb', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#e8f0fe' }}><span style={{ fontSize: '0.55rem', color: '#1e40af' }}>مساحة القاعدة الفعلية</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(fActualArea)} م²</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="result-tile" style={{ border: '1px solid #d97706', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#fef3c7' }}><span style={{ fontSize: '0.55rem', color: '#92400e' }}>ضغط التربة الفعلي</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(fPressure)} طن/م²</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="result-tile" style={{ border: '1px solid #d97706', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#fef3c7' }}><span style={{ fontSize: '0.55rem', color: '#92400e' }}>نسبة استغلال التربة</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(fUtilization)}%</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="result-tile" style={{ border: '1px solid #2563eb', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#e8f0fe' }}><span style={{ fontSize: '0.55rem', color: '#1e40af' }}>البروز الطولي / العرضي</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(overhangL)} / {fmt(overhangW)} م</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="result-tile" style={{ border: '1px solid #28a745', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: fSafe ? '#dcfce7' : '#fee2e2' }}><span style={{ fontSize: '0.55rem', color: '#555' }}>حالة القاعدة</span><strong style={{ fontSize: '1rem', color: fSafe ? '#059669' : '#dc2626', display: 'block' }}>{fSafe ? '✅ آمنة' : '❌ غير آمنة'}</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <SectionTitle>التشييك العكسي للقاعدة</SectionTitle>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="results-grid" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="result-tile" style={{ border: '1px solid #2563eb', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#e8f0fe' }}><span style={{ fontSize: '0.55rem', color: '#1e40af' }}>المساحة المطلوبة للقاعدة</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(fRequiredArea)} م²</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="result-tile" style={{ border: '1px solid #059669', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#ecfdf5' }}><span style={{ fontSize: '0.55rem', color: '#065f46' }}>ضلع مقترح (مربع)</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(fSuggestedSide)} م</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>{/* دراسة عمود نموذجي */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="model-card" style={{ border: '1px solid #ddd', borderRadius: '12px', overflow: 'hidden', background: 'white' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="model-head" onClick={() => setOpenColumn(!openColumn)} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 12px', background: '#f8fafc', cursor: 'pointer' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <span style={{ fontWeight: 700, color: '#003366', fontSize: '0.9rem' }}>🏛️ تشييك عمود فعلي</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <span>{openColumn ? '▲' : '▼'}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {openColumn && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="model-body" style={{ padding: '10px 12px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', marginBottom: '12px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <Num id="s-cload" label="حمل العمود (طن)" value={data.cLoad} set={(v: string) => update('cLoad', v)} unit="طن" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <Num id="s-clen" label="طول العمود (م)" value={data.cLength} set={(v: string) => update('cLength', v)} unit="م" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <Num id="s-cwid" label="عرض العمود (م)" value={data.cWidth} set={(v: string) => update('cWidth', v)} unit="م" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <Num id="s-cfcu" label="مقاومة الخرسانة fcu (MPa)" value={data.cFcu} set={(v: string) => update('cFcu', v)} unit="MPa" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <Num id="s-cbc" label="عدد أسياخ التسليح" value={data.cBarCount} set={(v: string) => update('cBarCount', v)} unit="سيخ" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <Num id="s-cbd" label="قطر التسليح (مم)" value={data.cBarDia} set={(v: string) => update('cBarDia', v)} unit="مم" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <SectionTitle>نتائج تشييك العمود</SectionTitle>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="results-grid" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="result-tile" style={{ border: '1px solid #2563eb', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#e8f0fe' }}><span style={{ fontSize: '0.55rem', color: '#1e40af' }}>مساحة مقطع العمود</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(cAg)} م²</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="result-tile" style={{ border: '1px solid #059669', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#ecfdf5' }}><span style={{ fontSize: '0.55rem', color: '#065f46' }}>قدرة تحمل العمود</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(cCapacity)} طن</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="result-tile" style={{ border: '1px solid #d97706', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#fef3c7' }}><span style={{ fontSize: '0.55rem', color: '#92400e' }}>نسبة الاستغلال</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(utilization)}%</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="result-tile" style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              border: '1px solid #28a745', borderRadius: '10px', padding: '10px 8px', textAlign: 'center',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        background: utilization <= 70 ? '#dcfce7' : utilization <= 90 ? '#fef3c7' : utilization <= 100 ? '#ffedd5' : '#fee2e2'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <span style={{ fontSize: '0.55rem', color: '#555' }}>حالة العمود</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <strong style={{ fontSize: '1rem', display: 'block', color: utilization <= 70 ? '#059669' : utilization <= 90 ? '#d97706' : utilization <= 100 ? '#ea580c' : '#dc2626' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {utilization <= 70 ? '✅ ممتاز' : utilization <= 90 ? '⚠️ جيد' : utilization <= 100 ? '⚠️ قريب من الحد' : '❌ غير آمن'}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </strong>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <SectionTitle>نتائج تشييك التسليح</SectionTitle>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="results-grid" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="result-tile" style={{ border: '1px solid #2563eb', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#e8f0fe' }}><span style={{ fontSize: '0.55rem', color: '#1e40af' }}>إجمالي مساحة الحديد</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(totalSteelCm2)} سم²</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="result-tile" style={{ border: '1px solid #7c3aed', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#f5f3ff' }}><span style={{ fontSize: '0.55rem', color: '#5b21b6' }}>نسبة التسليح</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(steelRatio)}%</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="result-tile" style={{ border: '1px solid #28a745', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: steelRatioOK ? '#dcfce7' : '#fee2e2' }}><span style={{ fontSize: '0.55rem', color: '#555' }}>حالة التسليح</span><strong style={{ fontSize: '1rem', color: steelRatioOK ? '#059669' : '#dc2626', display: 'block' }}>{steelRatioOK ? '✅ مناسب' : '❌ غير مناسب'}</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <SectionTitle>التشييك العكسي للعمود</SectionTitle>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="results-grid" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="result-tile" style={{ border: '1px solid #2563eb', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#e8f0fe' }}><span style={{ fontSize: '0.55rem', color: '#1e40af' }}>مساحة العمود المطلوبة</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(cRequiredArea)} م²</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="result-tile" style={{ border: '1px solid #059669', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: '#ecfdf5' }}><span style={{ fontSize: '0.55rem', color: '#065f46' }}>قطاع مقترح (مربع)</span><strong style={{ fontSize: '1rem', color: '#1e3a5f', display: 'block' }}>{fmt(cSuggestedSide)} × {fmt(cSuggestedSide)} م</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>      {/* التقييم النهائي */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="model-card" style={{ border: '1px solid #ddd', borderRadius: '12px', overflow: 'hidden', background: 'white' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="model-head" onClick={() => setOpenFinal(!openFinal)} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 12px', background: '#f8fafc', cursor: 'pointer' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <span style={{ fontWeight: 700, color: '#003366', fontSize: '0.9rem' }}>📊 التقييم النهائي</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <span>{openFinal ? '▲' : '▼'}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {openFinal && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="model-body" style={{ padding: '10px 12px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="results-grid" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="result-tile" style={{ border: '1px solid #d97706', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: soilOK ? '#dcfce7' : '#fee2e2' }}><span style={{ fontSize: '0.55rem', color: '#555' }}>التربة</span><strong style={{ fontSize: '1rem', color: soilOK ? '#059669' : '#dc2626', display: 'block' }}>{soilOK ? '✅ جيدة' : '❌ ضعيفة'}</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="result-tile" style={{ border: '1px solid #d97706', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: footingFinalOK ? '#dcfce7' : '#fee2e2' }}><span style={{ fontSize: '0.55rem', color: '#555' }}>القواعد</span><strong style={{ fontSize: '1rem', color: footingFinalOK ? '#059669' : '#dc2626', display: 'block' }}>{footingFinalOK ? '✅ آمنة' : '❌ غير آمنة'}</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="result-tile" style={{ border: '1px solid #d97706', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: columnFinalOK ? '#dcfce7' : '#fee2e2' }}><span style={{ fontSize: '0.55rem', color: '#555' }}>الأعمدة</span><strong style={{ fontSize: '1rem', color: columnFinalOK ? '#059669' : '#dc2626', display: 'block' }}>{utilization <= 70 ? '✅ ممتازة' : utilization <= 90 ? '⚠️ جيدة' : utilization <= 100 ? '⚠️ قريبة من الحد' : '❌ غير آمنة'}</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="result-tile" style={{ border: '1px solid #d97706', borderRadius: '10px', padding: '10px 8px', textAlign: 'center', background: steelFinalOK ? '#dcfce7' : '#fee2e2' }}><span style={{ fontSize: '0.55rem', color: '#555' }}>التسليح</span><strong style={{ fontSize: '1rem', color: steelFinalOK ? '#059669' : '#dc2626', display: 'block' }}>{steelFinalOK ? '✅ مناسب' : '❌ غير مناسب'}</strong></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {allOK && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div style={{ marginTop: '12px', padding: '10px', background: '#dcfce7', borderRadius: '10px', textAlign: 'center', fontWeight: 800, color: '#059669', fontSize: '0.9rem' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                🎉 جميع العناصر متوافقة مع متطلبات التصميم الأولي
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {/* أزرار أسفل الصفحة */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="no-print" style={{ display: 'flex', gap: '6px', padding: '12px 15px', background: 'white', borderTop: '1px solid #eee', marginTop: 'auto' }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <button onClick={reset} style={{ flex: 1, padding: '10px', border: 'none', borderRadius: '10px', background: '#dc3545', color: 'white', fontWeight: 700, fontSize: '0.8rem', cursor: 'pointer', fontFamily: 'Cairo, sans-serif' }}>تفريغ المدخلات</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <button onClick={calculate} style={{ flex: 1, padding: '10px', border: 'none', borderRadius: '10px', background: '#00509e', color: 'white', fontWeight: 700, fontSize: '0.8rem', cursor: 'pointer', fontFamily: 'Cairo, sans-serif' }}>حساب التشييك</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <button style={{ flex: 1, padding: '10px', border: 'none', borderRadius: '10px', background: '#28a745', color: 'white', fontWeight: 700, fontSize: '0.8rem', cursor: 'pointer', fontFamily: 'Cairo, sans-serif' }} onClick={() => window.print()}>🖨️ طباعة PDF</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  export default Structural;